  1	import * as React from 'react';
  2	import classNames from 'classnames';
  3	import { useTranslation } from 'react-i18next';
  4	import {
  5	  HistoryIcon,
  6	  InfoCircleIcon,
  7	  MonitoringIcon,
  8	} from '@patternfly/react-icons';
  9	import {
 10	  Alert,
 11	  Card,
 12	  CardBody,
 13	  CardTitle,
 14	  Divider,
 15	  Grid,
 16	  GridItem,
 17	} from '@patternfly/react-core';
 18	import { useFlag } from '@openshift-console/dynamic-plugin-sdk';
 19	import { SummaryProps, getFilter, useInterval } from './utils';
 20	import { getResultsSummary } from '../utils/summary-api';
 21	import { DataType, FLAGS } from '../../types';
 22	import { ALL_NAMESPACES_KEY } from '../../consts';
 23	import { formatTime, getDropDownDate } from './dateTime';
 24	import { LoadingInline } from '../Loading';
 25	
 26	import './PipelineRunsDurationCard.scss';
 27	
 28	interface PipelinesRunsDurationProps {
 29	  namespace: string;
 30	  timespan: number;
 31	  interval: number;
 32	  parentName?: string;
 33	  summaryData?: SummaryProps;
 34	  bordered?: boolean;
 35	  kind?: string;
 36	}
 37	
 38	const PipelinesRunsDurationCard: React.FC<PipelinesRunsDurationProps> = ({
 39	  namespace,
 40	  timespan,
 41	  parentName,
 42	  interval,
 43	  bordered,
 44	  kind,
 45	}) => {
 46	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 47	  const isDevConsoleProxyAvailable = useFlag(FLAGS.DEVCONSOLE_PROXY);
 48	  const [summaryData, setSummaryData] = React.useState<SummaryProps>({});
 49	  const [loaded, setLoaded] = React.useState(false);
 50	  const [pipelineRunsDurationError, setPipelineRunsDurationError] =
 51	    React.useState<string | undefined>();
 52	  const abortControllerRef = React.useRef<AbortController>();
 53	
 54	  if (namespace == ALL_NAMESPACES_KEY) {
 55	    namespace = '-';
 56	  }
 57	
 58	  React.useEffect(() => {
 59	    setLoaded(false);
 60	    setPipelineRunsDurationError(undefined);
 61	    setSummaryData({});
 62	  }, [namespace, timespan]);
 63	
 64	  React.useEffect(() => {
 65	    return () => {
 66	      abortControllerRef.current?.abort();
 67	    };
 68	  }, []);
 69	
 70	  const date = getDropDownDate(timespan).toISOString();
 71	
 72	  const getSummaryData = () => {
 73	    abortControllerRef.current?.abort();
 74	    abortControllerRef.current = new AbortController();
 75	    setSummaryData({});
 76	    setPipelineRunsDurationError(undefined);
 77	    setLoaded(false);
 78	    getResultsSummary(
 79	      namespace,
 80	      {
 81	        summary: 'total_duration,avg_duration,max_duration',
 82	        data_type: DataType?.PipelineRun,
 83	        filter: getFilter(date, parentName, kind),
 84	      },
 85	      undefined,
 86	      isDevConsoleProxyAvailable,
 87	      abortControllerRef.current.signal,
 88	      90000, // increase timeout to 90 seconds
 89	    )
 90	      .then((response) => {
 91	        setLoaded(true);
 92	        setPipelineRunsDurationError(undefined);
 93	        setSummaryData(response.summary?.[0]);
 94	      })
 95	      .catch((e) => {
 96	        if (e.name === 'AbortError') {
 97	          return;
 98	        }
 99	        // Don't log to console, just show user-facing error
100	        setLoaded(true);
101	        setPipelineRunsDurationError(
102	          e.message || t('Failed to load duration data'),
103	        );
104	        // Clear stale data on error
105	        setSummaryData({});
106	      });
107	  };
108	
109	  useInterval(getSummaryData, interval, namespace, date);
110	
111	  return (
112	    <>
113	      <Card
114	        className={classNames('pipeline-overview__duration-card', {
115	          'card-border': bordered,
116	        })}
117	      >
118	        <CardTitle>
119	          <span>{t('Duration')}</span>
120	        </CardTitle>
121	        <Divider />
122	        <CardBody>
123	          {pipelineRunsDurationError ? (
124	            <Alert
125	              variant="danger"
126	              isInline
127	              title={t('Unable to load duration')}
128	              className="pf-v6-u-mb-md"
129	            />
130	          ) : (
131	            <>
132	              <Grid
133	                hasGutter
134	                className="pipeline-overview__duration-card__grid"
135	              >
136	                <GridItem span={6}>
137	                  <span>
138	                    <MonitoringIcon className="pipeline-overview__duration-card__icon" />
139	                    {t('Average duration')}
140	                  </span>
141	                </GridItem>
142	                <GridItem
143	                  span={6}
144	                  className="pipeline-overview__duration-card__value"
145	                >
146	                  {loaded ? (
147	                    summaryData?.['avg_duration'] ? (
148	                      formatTime(summaryData?.['avg_duration'])
149	                    ) : (
150	                      '-'
151	                    )
152	                  ) : (
153	                    <LoadingInline />
154	                  )}
155	                </GridItem>
156	              </Grid>
157	              <Grid
158	                hasGutter
159	                className="pipeline-overview__duration-card__grid"
160	              >
161	                <GridItem span={6}>
162	                  <span>
163	                    <InfoCircleIcon className="pipeline-overview__duration-card__info-icon" />
164	                    {t('Maximum')}
165	                  </span>
166	                </GridItem>
167	                <GridItem
168	                  span={6}
169	                  className="pipeline-overview__duration-card__value"
170	                >
171	                  {loaded ? (
172	                    summaryData?.['max_duration'] ? (
173	                      formatTime(summaryData?.['max_duration'])
174	                    ) : (
175	                      '-'
176	                    )
177	                  ) : (
178	                    <LoadingInline />
179	                  )}
180	                </GridItem>
181	              </Grid>
182	              <Grid hasGutter>
183	                <GridItem span={6}>
184	                  <span>
185	                    <HistoryIcon className="pipeline-overview__duration-card__icon" />
186	                    {t('Total duration')}
187	                  </span>
188	                </GridItem>
189	                <GridItem
190	                  span={6}
191	                  className="pipeline-overview__duration-card__value"
192	                >
193	                  {loaded ? (
194	                    summaryData?.['total_duration'] ? (
195	                      formatTime(summaryData?.['total_duration'])
196	                    ) : (
197	                      '-'
198	                    )
199	                  ) : (
200	                    <LoadingInline />
201	                  )}
202	                </GridItem>
203	              </Grid>
204	            </>
205	          )}
206	        </CardBody>
207	      </Card>
208	    </>
209	  );
210	};
211	
212	export default PipelinesRunsDurationCard;

